// Script Continued Below
// STRY0074135 - the parent task for the grafted in template did not update to set the child template run
tasker_2_6_300_updateTopOUs();

function tasker_2_6_300_updateTopOUs(){
	var countEmptyTopOUs = 0;
	// get counts for OUs without Top OU
	var agTopOU = new GlideAggregate("x_153465_discovert_discover_office_hierarchy");
	agTopOU.addNullQuery('u_top_ou');
	agTopOU.addAggregate("COUNT");	
	agTopOU.query();
	if(agTopOU.next()){
		countEmptyTopOUs = agTopOU.getAggregate("COUNT");
	}

	gs.info('Fix Script - Tasker 2.6.300- Set Top OUs.  Number of TopOUs not set - ' + countEmptyTopOUs + '.  Setting TopOUs...');

	// all that should be needed is to set the top ou's top ou
	// the business rules should handle setting all of the child OU's top ou fields
	var grTopOUs = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
	grTopOUs.addNullQuery('parent');
	grTopOUs.query();
	while(grTopOUs.next()){
		grTopOUs.u_top_ou = grTopOUs.getUniqueValue();
		grTopOUs.update();
	}

	var afterCountEmptyTopOUs;
	var agAfterTopOU = new GlideAggregate("x_153465_discovert_discover_office_hierarchy");
	agAfterTopOU.addNullQuery('u_top_ou');
	agAfterTopOU.addAggregate("COUNT");	
	agAfterTopOU.query();
	if(agAfterTopOU.next()){
		afterCountEmptyTopOUs = agAfterTopOU.getAggregate("COUNT");
	}

	if(afterCountEmptyTopOUs == 0){
		gs.info('Fix Script - Tasker 2.6.300- All Top (' + countEmptyTopOUs + ') OUs were set correctly by the Fix Script.');
	} else {
		gs.info('Fix Script - Tasker 2.6.300- Found (' + countEmptyTopOUs + ') Top OUs not set.  The Fix Script was not able to set (' + afterCountEmptyTopOUs + ') Top OUs.');
	}	
}
